import React, { useState, useEffect } from 'react';
import api from '../services/api';

const CrearOferta = () => {
  const [formData, setFormData] = useState({
    programa_formacion: '',
    modalidad: '',
    tipo_programa: '',
    tipo_oferta: '',
    cupo_maximo: '',
    ambiente: {
      nombre: '',
      codigo: '',
      capacidad: '',
      ubicacion_fisica: '',
      recursos_disponibles: [],
      estado: 'disponible'
    },
    modelo_ambiente: {
      nombre: '',
      descripcion: '',
      capacidad_recomendada: '',
      recursos: []
    },
    fechas: {
      inicio: '',
      fin: ''
    },
    ubicacion: {
      departamento: 'Cauca',
      municipio: '',
      direccion: ''
    },
    empresa_solicitante: {
      nombre: '',
      nit: '',
      contacto: {
        nombre: '',
        cargo: '',
        telefono: '',
        correo: ''
      },
      direccion: '',
      telefono: '',
      correo: ''
    },
    subsector_economico: {
      codigo: '',
      nombre: '',
      sector_principal: '',
      descripcion: ''
    },
    convenio: {
      nombre: '',
      codigo: '',
      fecha_inicio: '',
      fecha_fin: '',
      entidad_aliada: '',
      descripcion: '',
      documento_url: ''
    },
    programa_especial: '',
    horario: {
      hora_inicio: '08:00',
      hora_fin: '12:00',
      dias: []
    },
    firma_digital: {
      tipo: 'electronica',
      documento_pdf_url: '',
      fecha_firma: new Date().toISOString().split('T')[0]
    },
    observaciones: ''
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  // Estados para las opciones de los selects (vienen de MongoDB)
  const [programas, setProgramas] = useState([]);
  const [modalidades, setModalidades] = useState([]);
  const [tiposPrograma, setTiposPrograma] = useState([]);
  const [tiposOferta, setTiposOferta] = useState([]);
  const [municipios, setMunicipios] = useState([]);
  const [programasEspeciales, setProgramasEspeciales] = useState([]);

  // Cargar datos de MongoDB al montar el componente
  useEffect(() => {
    cargarDatosIniciales();
  }, []);

  const cargarDatosIniciales = async () => {
    try {
      const [
        programasRes,
        modalidadesRes,
        tiposProgramaRes,
        tiposOfertaRes,
        municipiosRes,
        programasEspecialesRes
      ] = await Promise.all([
        api.get('/programas-formacion'),
        api.get('/modalidades'),
        api.get('/tipos-programa'),
        api.get('/tipos-oferta'),
        api.get('/municipios'),
        api.get('/programas-especiales')
      ]);

      setProgramas(programasRes.data.data || []);
      setModalidades(modalidadesRes.data.data || []);
      setTiposPrograma(tiposProgramaRes.data.data || []);
      setTiposOferta(tiposOfertaRes.data.data || []);
      setMunicipios(municipiosRes.data.data || []);
      setProgramasEspeciales(programasEspecialesRes.data.data || []);
    } catch (error) {
      console.error('Error cargando datos:', error);
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    
    // Manejar campos anidados (ej: "empresa_solicitante.nombre")
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setFormData({
        ...formData,
        [parent]: {
          ...formData[parent],
          [child]: value
        }
      });
    } 
    // Manejar campos anidados de nivel 3 (ej: "empresa_solicitante.contacto.nombre")
    else if (name.split('.').length === 3) {
      const [parent, child, subchild] = name.split('.');
      setFormData({
        ...formData,
        [parent]: {
          ...formData[parent],
          [child]: {
            ...formData[parent][child],
            [subchild]: value
          }
        }
      });
    }
    else {
      setFormData({
        ...formData,
        [name]: value
      });
    }
  };

  const handleRecursoChange = (e, tipo, index) => {
    const { value } = e.target;
    const nuevosRecursos = [...formData[tipo].recursos];
    nuevosRecursos[index] = value;
    
    setFormData({
      ...formData,
      [tipo]: {
        ...formData[tipo],
        recursos: nuevosRecursos
      }
    });
  };

  const agregarRecurso = (tipo) => {
    setFormData({
      ...formData,
      [tipo]: {
        ...formData[tipo],
        recursos: [...formData[tipo].recursos, '']
      }
    });
  };

  const quitarRecurso = (tipo, index) => {
    const nuevosRecursos = formData[tipo].recursos.filter((_, i) => i !== index);
    setFormData({
      ...formData,
      [tipo]: {
        ...formData[tipo],
        recursos: nuevosRecursos
      }
    });
  };

  const handleDiaChange = (e) => {
    const { value, checked } = e.target;
    if (checked) {
      setFormData({
        ...formData,
        horario: {
          ...formData.horario,
          dias: [...formData.horario.dias, value]
        }
      });
    } else {
      setFormData({
        ...formData,
        horario: {
          ...formData.horario,
          dias: formData.horario.dias.filter(dia => dia !== value)
        }
      });
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setSuccess('');

    try {
      // Validar campos requeridos
      if (!formData.programa_formacion) throw new Error('Seleccione un programa de formación');
      if (!formData.modalidad) throw new Error('Seleccione una modalidad');
      if (!formData.tipo_programa) throw new Error('Seleccione un tipo de programa');
      if (!formData.tipo_oferta) throw new Error('Seleccione un tipo de oferta');
      if (!formData.cupo_maximo) throw new Error('Ingrese el cupo máximo');
      if (!formData.ambiente.nombre) throw new Error('Ingrese el nombre del ambiente');
      if (!formData.modelo_ambiente.nombre) throw new Error('Ingrese el modelo de ambiente');
      if (!formData.fechas.inicio || !formData.fechas.fin) throw new Error('Ingrese las fechas');
      if (!formData.ubicacion.municipio) throw new Error('Seleccione un municipio');
      if (!formData.empresa_solicitante.nombre) throw new Error('Ingrese el nombre de la empresa');
      if (!formData.empresa_solicitante.nit) throw new Error('Ingrese el NIT');
      if (!formData.subsector_economico.nombre) throw new Error('Ingrese el subsector económico');
      if (formData.horario.dias.length === 0) throw new Error('Seleccione al menos un día');

      // Validar fechas
      const fechaInicio = new Date(formData.fechas.inicio);
      const fechaFin = new Date(formData.fechas.fin);
      if (fechaFin <= fechaInicio) {
        throw new Error('La fecha de fin debe ser posterior a la fecha de inicio');
      }

      // Limpiar recursos vacíos
      const datosEnvio = {
        ...formData,
        ambiente: {
          ...formData.ambiente,
          recursos_disponibles: formData.ambiente.recursos_disponibles.filter(r => r.trim() !== '')
        },
        modelo_ambiente: {
          ...formData.modelo_ambiente,
          recursos: formData.modelo_ambiente.recursos.filter(r => r.trim() !== '')
        }
      };

      console.log('Enviando datos:', datosEnvio);
      
      const response = await api.post('/ofertas', datosEnvio);
      
      setSuccess('✅ Oferta creada exitosamente');
      console.log('Respuesta:', response.data);
      
      // Limpiar formulario
      setTimeout(() => {
        window.location.reload();
      }, 2000);
      
    } catch (error) {
      console.error('Error:', error);
      setError(error.response?.data?.message || error.message);
    } finally {
      setLoading(false);
    }
  };

  const diasSemana = ['Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado', 'Domingo'];

  return (
    <div style={styles.container}>
      <h2 style={styles.title}>➕ Crear Nueva Oferta en MongoDB</h2>
      
      {error && (
        <div style={styles.errorAlert}>
          ❌ {error}
        </div>
      )}
      
      {success && (
        <div style={styles.successAlert}>
          {success}
        </div>
      )}

      <form onSubmit={handleSubmit} style={styles.form}>
        
        {/* SECCIÓN 1: PROGRAMA DE FORMACIÓN */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Programa de Formación</h3>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Programa:</label>
            <select 
              name="programa_formacion"
              value={formData.programa_formacion}
              onChange={handleChange}
              style={styles.select}
              required
            >
              <option value="">Seleccione...</option>
              {programas.map(prog => (
                <option key={prog._id} value={prog._id}>
                  {prog.nombre_programa} - {prog.codigo}
                </option>
              ))}
            </select>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Modalidad:</label>
            <select 
              name="modalidad"
              value={formData.modalidad}
              onChange={handleChange}
              style={styles.select}
              required
            >
              <option value="">Seleccione...</option>
              {modalidades.map(mod => (
                <option key={mod._id} value={mod._id}>
                  {mod.nombre}
                </option>
              ))}
            </select>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Tipo de Programa:</label>
            <select 
              name="tipo_programa"
              value={formData.tipo_programa}
              onChange={handleChange}
              style={styles.select}
              required
            >
              <option value="">Seleccione...</option>
              {tiposPrograma.map(tp => (
                <option key={tp._id} value={tp._id}>
                  {tp.nombre}
                </option>
              ))}
            </select>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Tipo de Oferta:</label>
            <select 
              name="tipo_oferta"
              value={formData.tipo_oferta}
              onChange={handleChange}
              style={styles.select}
              required
            >
              <option value="">Seleccione...</option>
              {tiposOferta.map(to => (
                <option key={to._id} value={to._id}>
                  {to.nombre}
                </option>
              ))}
            </select>
          </div>
        </div>

        {/* SECCIÓN 2: CUPOS */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Cupos</h3>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Cupo Máximo:</label>
            <input 
              type="number"
              name="cupo_maximo"
              value={formData.cupo_maximo}
              onChange={handleChange}
              style={styles.input}
              placeholder="30"
              min="1"
              required
            />
          </div>
        </div>

        {/* SECCIÓN 3: AMBIENTE */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Ambiente</h3>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Nombre del Ambiente:</label>
            <input 
              type="text"
              name="ambiente.nombre"
              value={formData.ambiente.nombre}
              onChange={handleChange}
              style={styles.input}
              placeholder="Aula 101"
              required
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Código:</label>
            <input 
              type="text"
              name="ambiente.codigo"
              value={formData.ambiente.codigo}
              onChange={handleChange}
              style={styles.input}
              placeholder="AULA-101"
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Capacidad:</label>
            <input 
              type="number"
              name="ambiente.capacidad"
              value={formData.ambiente.capacidad}
              onChange={handleChange}
              style={styles.input}
              placeholder="35"
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Ubicación Física:</label>
            <input 
              type="text"
              name="ambiente.ubicacion_fisica"
              value={formData.ambiente.ubicacion_fisica}
              onChange={handleChange}
              style={styles.input}
              placeholder="Edificio Principal, Piso 1"
            />
          </div>
        </div>

        {/* SECCIÓN 4: MODELO DE AMBIENTE */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Modelo de Ambiente</h3>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Nombre del Modelo:</label>
            <input 
              type="text"
              name="modelo_ambiente.nombre"
              value={formData.modelo_ambiente.nombre}
              onChange={handleChange}
              style={styles.input}
              placeholder="Aula Virtual"
              required
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Descripción:</label>
            <textarea
              name="modelo_ambiente.descripcion"
              value={formData.modelo_ambiente.descripcion}
              onChange={handleChange}
              style={styles.textarea}
              rows="2"
              placeholder="Descripción del modelo..."
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Capacidad Recomendada:</label>
            <input 
              type="number"
              name="modelo_ambiente.capacidad_recomendada"
              value={formData.modelo_ambiente.capacidad_recomendada}
              onChange={handleChange}
              style={styles.input}
              placeholder="30"
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Recursos del Modelo:</label>
            {formData.modelo_ambiente.recursos.map((recurso, index) => (
              <div key={index} style={styles.recursoRow}>
                <input
                  type="text"
                  value={recurso}
                  onChange={(e) => handleRecursoChange(e, 'modelo_ambiente', index)}
                  style={styles.recursoInput}
                  placeholder={`Recurso ${index + 1}`}
                />
                <button
                  type="button"
                  onClick={() => quitarRecurso('modelo_ambiente', index)}
                  style={styles.quitarRecursoBtn}
                >
                  ✕
                </button>
              </div>
            ))}
            <button
              type="button"
              onClick={() => agregarRecurso('modelo_ambiente')}
              style={styles.agregarBtn}
            >
              + Agregar Recurso
            </button>
          </div>
        </div>

        {/* SECCIÓN 5: FECHAS */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Fechas</h3>
          
          <div style={styles.row}>
            <div style={styles.half}>
              <label style={styles.label}>Fecha Inicio:</label>
              <input 
                type="date"
                name="fechas.inicio"
                value={formData.fechas.inicio}
                onChange={handleChange}
                style={styles.input}
                required
              />
            </div>
            <div style={styles.half}>
              <label style={styles.label}>Fecha Fin:</label>
              <input 
                type="date"
                name="fechas.fin"
                value={formData.fechas.fin}
                onChange={handleChange}
                style={styles.input}
                required
              />
            </div>
          </div>
        </div>

        {/* SECCIÓN 6: UBICACIÓN */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Ubicación</h3>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Departamento:</label>
            <input 
              type="text"
              name="ubicacion.departamento"
              value={formData.ubicacion.departamento}
              onChange={handleChange}
              style={styles.input}
              placeholder="Cauca"
              required
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Municipio:</label>
            <select 
              name="ubicacion.municipio"
              value={formData.ubicacion.municipio}
              onChange={handleChange}
              style={styles.select}
              required
            >
              <option value="">Seleccione...</option>
              {municipios.map(mun => (
                <option key={mun._id} value={mun._id}>
                  {mun.nombre}
                </option>
              ))}
            </select>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Dirección:</label>
            <input 
              type="text"
              name="ubicacion.direccion"
              value={formData.ubicacion.direccion}
              onChange={handleChange}
              style={styles.input}
              placeholder="Dirección específica"
            />
          </div>
        </div>

        {/* SECCIÓN 7: EMPRESA SOLICITANTE */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Empresa Solicitante</h3>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Nombre de la Empresa:</label>
            <input 
              type="text"
              name="empresa_solicitante.nombre"
              value={formData.empresa_solicitante.nombre}
              onChange={handleChange}
              style={styles.input}
              placeholder="Empresa SAS"
              required
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>NIT:</label>
            <input 
              type="text"
              name="empresa_solicitante.nit"
              value={formData.empresa_solicitante.nit}
              onChange={handleChange}
              style={styles.input}
              placeholder="123456789-0"
              required
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Teléfono:</label>
            <input 
              type="text"
              name="empresa_solicitante.telefono"
              value={formData.empresa_solicitante.telefono}
              onChange={handleChange}
              style={styles.input}
              placeholder="6021234567"
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Correo:</label>
            <input 
              type="email"
              name="empresa_solicitante.correo"
              value={formData.empresa_solicitante.correo}
              onChange={handleChange}
              style={styles.input}
              placeholder="contacto@empresa.com"
            />
          </div>

          <h4 style={styles.subsectionTitle}>Contacto</h4>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Nombre del Contacto:</label>
            <input 
              type="text"
              name="empresa_solicitante.contacto.nombre"
              value={formData.empresa_solicitante.contacto.nombre}
              onChange={handleChange}
              style={styles.input}
              placeholder="Juan Pérez"
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Cargo:</label>
            <input 
              type="text"
              name="empresa_solicitante.contacto.cargo"
              value={formData.empresa_solicitante.contacto.cargo}
              onChange={handleChange}
              style={styles.input}
              placeholder="Gerente"
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Teléfono del Contacto:</label>
            <input 
              type="text"
              name="empresa_solicitante.contacto.telefono"
              value={formData.empresa_solicitante.contacto.telefono}
              onChange={handleChange}
              style={styles.input}
              placeholder="3001234567"
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Correo del Contacto:</label>
            <input 
              type="email"
              name="empresa_solicitante.contacto.correo"
              value={formData.empresa_solicitante.contacto.correo}
              onChange={handleChange}
              style={styles.input}
              placeholder="juan@empresa.com"
            />
          </div>
        </div>

        {/* SECCIÓN 8: SUBSECTOR ECONÓMICO */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Subsector Económico</h3>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Nombre:</label>
            <input 
              type="text"
              name="subsector_economico.nombre"
              value={formData.subsector_economico.nombre}
              onChange={handleChange}
              style={styles.input}
              placeholder="Tecnologías de la Información"
              required
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Código:</label>
            <input 
              type="text"
              name="subsector_economico.codigo"
              value={formData.subsector_economico.codigo}
              onChange={handleChange}
              style={styles.input}
              placeholder="TIC-01"
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Sector Principal:</label>
            <input 
              type="text"
              name="subsector_economico.sector_principal"
              value={formData.subsector_economico.sector_principal}
              onChange={handleChange}
              style={styles.input}
              placeholder="Educación y Tecnología"
            />
          </div>
        </div>

        {/* SECCIÓN 9: CONVENIO */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Convenio</h3>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Nombre del Convenio:</label>
            <input 
              type="text"
              name="convenio.nombre"
              value={formData.convenio.nombre}
              onChange={handleChange}
              style={styles.input}
              placeholder="Convenio SENA - Alcaldía"
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Código:</label>
            <input 
              type="text"
              name="convenio.codigo"
              value={formData.convenio.codigo}
              onChange={handleChange}
              style={styles.input}
              placeholder="CONV-2026-001"
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Entidad Aliada:</label>
            <input 
              type="text"
              name="convenio.entidad_aliada"
              value={formData.convenio.entidad_aliada}
              onChange={handleChange}
              style={styles.input}
              placeholder="Alcaldía de Popayán"
            />
          </div>
        </div>

        {/* SECCIÓN 10: PROGRAMA ESPECIAL */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Programa Especial</h3>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Programa Especial:</label>
            <select 
              name="programa_especial"
              value={formData.programa_especial}
              onChange={handleChange}
              style={styles.select}
            >
              <option value="">Ninguno</option>
              {programasEspeciales.map(pe => (
                <option key={pe._id} value={pe._id}>
                  {pe.nombre}
                </option>
              ))}
            </select>
          </div>
        </div>

        {/* SECCIÓN 11: HORARIO */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Horario</h3>
          
          <div style={styles.row}>
            <div style={styles.half}>
              <label style={styles.label}>Hora Inicio:</label>
              <input 
                type="time"
                name="horario.hora_inicio"
                value={formData.horario.hora_inicio}
                onChange={handleChange}
                style={styles.input}
                required
              />
            </div>
            <div style={styles.half}>
              <label style={styles.label}>Hora Fin:</label>
              <input 
                type="time"
                name="horario.hora_fin"
                value={formData.horario.hora_fin}
                onChange={handleChange}
                style={styles.input}
                required
              />
            </div>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Días:</label>
            <div style={styles.checkboxGroup}>
              {diasSemana.map(dia => (
                <label key={dia} style={styles.checkboxLabel}>
                  <input 
                    type="checkbox"
                    value={dia}
                    checked={formData.horario.dias.includes(dia)}
                    onChange={handleDiaChange}
                  /> {dia}
                </label>
              ))}
            </div>
          </div>
        </div>

        {/* SECCIÓN 12: OBSERVACIONES */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Información Adicional</h3>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Observaciones:</label>
            <textarea
              name="observaciones"
              value={formData.observaciones}
              onChange={handleChange}
              style={styles.textarea}
              rows="3"
              placeholder="Observaciones adicionales..."
            />
          </div>
        </div>

        {/* BOTÓN DE ENVÍO */}
        <button 
          type="submit" 
          style={loading ? {...styles.submitButton, ...styles.buttonDisabled} : styles.submitButton}
          disabled={loading}
        >
          {loading ? 'Guardando...' : 'Guardar Oferta en MongoDB'}
        </button>
      </form>
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '1000px',
    margin: '0 auto',
    padding: '20px'
  },
  title: {
    color: '#2c3e50',
    borderBottom: '3px solid #3498db',
    paddingBottom: '10px',
    marginBottom: '30px',
    fontSize: '28px'
  },
  section: {
    backgroundColor: '#f8f9fa',
    padding: '20px',
    borderRadius: '8px',
    marginBottom: '25px',
    border: '1px solid #e0e0e0'
  },
  sectionTitle: {
    color: '#2c3e50',
    marginTop: 0,
    marginBottom: '20px',
    fontSize: '20px',
    borderBottom: '1px solid #3498db',
    paddingBottom: '5px'
  },
  subsectionTitle: {
    color: '#34495e',
    margin: '15px 0 10px 0',
    fontSize: '16px'
  },
  form: {
    display: 'flex',
    flexDirection: 'column',
    gap: '20px'
  },
  formGroup: {
    display: 'flex',
    flexDirection: 'column',
    gap: '5px',
    marginBottom: '15px'
  },
  row: {
    display: 'flex',
    gap: '20px',
    marginBottom: '15px'
  },
  half: {
    flex: 1,
    display: 'flex',
    flexDirection: 'column',
    gap: '5px'
  },
  label: {
    fontSize: '14px',
    fontWeight: 'bold',
    color: '#34495e'
  },
  input: {
    padding: '10px',
    border: '1px solid #ddd',
    borderRadius: '4px',
    fontSize: '14px',
    transition: 'border-color 0.3s',
    outline: 'none',
    ':focus': {
      borderColor: '#3498db'
    }
  },
  select: {
    padding: '10px',
    border: '1px solid #ddd',
    borderRadius: '4px',
    fontSize: '14px',
    backgroundColor: 'white',
    cursor: 'pointer'
  },
  textarea: {
    padding: '10px',
    border: '1px solid #ddd',
    borderRadius: '4px',
    fontSize: '14px',
    resize: 'vertical',
    fontFamily: 'Arial, sans-serif'
  },
  recursoRow: {
    display: 'flex',
    gap: '10px',
    marginBottom: '10px'
  },
  recursoInput: {
    flex: 1,
    padding: '8px',
    border: '1px solid #ddd',
    borderRadius: '4px',
    fontSize: '14px'
  },
  quitarRecursoBtn: {
    padding: '8px 12px',
    backgroundColor: '#e74c3c',
    color: 'white',
    border: 'none',
    borderRadius: '4px',
    cursor: 'pointer',
    fontSize: '12px'
  },
  agregarBtn: {
    padding: '8px 12px',
    backgroundColor: '#3498db',
    color: 'white',
    border: 'none',
    borderRadius: '4px',
    cursor: 'pointer',
    fontSize: '14px',
    marginTop: '5px'
  },
  checkboxGroup: {
    display: 'flex',
    flexWrap: 'wrap',
    gap: '15px',
    padding: '10px 0'
  },
  checkboxLabel: {
    display: 'flex',
    alignItems: 'center',
    gap: '5px',
    fontSize: '14px',
    cursor: 'pointer'
  },
  submitButton: {
    backgroundColor: '#27ae60',
    color: 'white',
    padding: '18px',
    border: 'none',
    borderRadius: '8px',
    fontSize: '18px',
    fontWeight: 'bold',
    cursor: 'pointer',
    marginTop: '20px',
    transition: 'background-color 0.3s'
  },
  buttonDisabled: {
    backgroundColor: '#95a5a6',
    cursor: 'not-allowed'
  },
  errorAlert: {
    backgroundColor: '#f8d7da',
    color: '#721c24',
    padding: '15px',
    borderRadius: '4px',
    marginBottom: '20px',
    border: '1px solid #f5c6cb',
    fontSize: '14px'
  },
  successAlert: {
    backgroundColor: '#d4edda',
    color: '#155724',
    padding: '15px',
    borderRadius: '4px',
    marginBottom: '20px',
    border: '1px solid #c3e6cb',
    fontSize: '14px'
  }
};

export default CrearOferta;
